import {
  component$,
  type NoSerialize,
  noSerialize,
} from "@builder.io/qwik";
import {
  Form,
  routeAction$,
  routeLoader$,
  zod$,
  z,
} from "@builder.io/qwik-city";
import { getAllComments, addComment, type CommentRow } from "../db";
import { CommentNode } from "../components/comment-node";

// ---- Tree types ----
export interface TreeNode extends CommentRow {
  children: TreeNode[];
  replyCount: number; // total nested descendants
}

// ---- Build a nested tree (with total descendant counts) from a flat list ----
function buildTree(rows: CommentRow[]): TreeNode[] {
  const nodes = new Map<number, TreeNode>();
  for (const r of rows) {
    nodes.set(r.id, { ...r, children: [], replyCount: 0 });
  }

  const roots: TreeNode[] = [];
  for (const node of nodes.values()) {
    if (node.parent_id == null) {
      roots.push(node);
    } else {
      const parent = nodes.get(node.parent_id);
      if (parent) {
        parent.children.push(node);
      } else {
        // orphan (parent missing) -> treat as root
        roots.push(node);
      }
    }
  }

  // Compute total descendant counts bottom-up.
  const countDescendants = (n: TreeNode): number => {
    let total = 0;
    for (const c of n.children) {
      total += 1 + countDescendants(c);
    }
    n.replyCount = total;
    return total;
  };
  for (const root of roots) {
    countDescendants(root);
  }

  // Sort children by id for stable ordering.
  const sortRecursive = (n: TreeNode) => {
    n.children.sort((a, b) => a.id - b.id);
    for (const c of n.children) sortRecursive(c);
  };
  for (const root of roots) sortRecursive(root);
  roots.sort((a, b) => a.id - b.id);

  return roots;
}

// ---- Loader: load all comments on the server and build the tree ----
export const useCommentsTree = routeLoader$(() => {
  const rows = getAllComments();
  const tree = buildTree(rows);
  // noSerialize keeps the plain data serializable for client handoff
  return noSerialize(tree) as unknown as TreeNode[];
});

// ---- Action: add a reply (or top-level comment) ----
export const useAddComment = routeAction$(
  async (data, { fail }) => {
    const author = (data.author ?? "").toString().trim();
    const body = (data.body ?? "").toString().trim();
    if (!author || !body) {
      return fail(400, {
        error: "Author and body are both required.",
        author: data.author ?? "",
        body: data.body ?? "",
      });
    }

    const rawParent = data.parent_id;
    const parentId =
      rawParent == null || rawParent === "" || rawParent === "null"
        ? null
        : Number(rawParent);

    if (parentId != null && (!Number.isInteger(parentId) || parentId <= 0)) {
      return fail(400, {
        error: "Invalid parent comment.",
        author: data.author ?? "",
        body: data.body ?? "",
      });
    }

    addComment(parentId, author, body);
    return { success: true };
  },
  zod$({
    author: z.string(),
    body: z.string(),
    parent_id: z.string().optional(),
  })
);

export default component$(() => {
  const tree = useCommentsTree();
  const action = useAddComment();

  return (
    <div class="app">
      <h1>Threaded Comments</h1>

      <div class="top-form">
        <h2>Add a comment</h2>
        <Form action={action}>
          <input type="hidden" name="parent_id" value="" />
          <div>
            <input
              type="text"
              name="author"
              placeholder="Your name"
              value={action.value?.failed ? (action.value.author as string) : ""}
            />
          </div>
          <div>
            <textarea name="body" placeholder="What's on your mind?"></textarea>
          </div>
          <button type="submit">Post comment</button>
          {action.value?.failed && (
            <div class="error">{action.value.error}</div>
          )}
        </Form>
      </div>

      <div class="thread">
        {tree.map((node) => (
          <CommentNode key={node.id} node={node} depth={0} action={action} />
        ))}
      </div>
    </div>
  );
});

import { component$, useSignal, type QRL } from "@builder.io/qwik";
import { Form, type ActionStore } from "@builder.io/qwik-city";
import type { TreeNode } from "../routes/index";

interface Props {
  node: TreeNode;
  depth: number;
  action: ActionStore<any, any, boolean>;
}

export const CommentNode = component$<Props>(({ node, depth, action }) => {
  // Per-subtree collapse state.
  const collapsed = useSignal(false);
  const showReplyForm = useSignal(false);

  const hasReplies = node.children.length > 0;

  return (
    <div
      class="comment"
      data-comment-id={String(node.id)}
      data-depth={String(depth)}
    >
      <div class="comment-header">
        <span class="comment-author">{node.author}</span>
        <span class="comment-meta">{new Date(node.created_at).toLocaleString()}</span>
        <span class="reply-count" data-reply-count={String(node.replyCount)}>
          {node.replyCount} {node.replyCount === 1 ? "reply" : "replies"}
        </span>
        {hasReplies && (
          <button
            type="button"
            class="toggle"
            data-testid={`toggle-${node.id}`}
            aria-expanded={!collapsed.value}
            onClick$={() => {
              collapsed.value = !collapsed.value;
            }}
          >
            {collapsed.value ? "[+] expand" : "[-] collapse"}
          </button>
        )}
        <button
          type="button"
          class="toggle"
          onClick$={() => {
            showReplyForm.value = !showReplyForm.value;
          }}
        >
          {showReplyForm.value ? "cancel" : "reply"}
        </button>
      </div>

      <div class="comment-body">{node.body}</div>

      {showReplyForm.value && (
        <Form action={action}>
          <input type="hidden" name="parent_id" value={String(node.id)} />
          <input
            type="text"
            name="author"
            placeholder="Your name"
            value={action.value?.failed ? (action.value.author as string) : ""}
          />
          <textarea name="body" placeholder="Your reply"></textarea>
          <button type="submit">Post reply</button>
          {action.value?.failed && (
            <div class="error">{action.value.error}</div>
          )}
        </Form>
      )}

      {hasReplies && !collapsed.value && (
        <div class="children">
          {node.children.map((child) => (
            <CommentNode
              key={child.id}
              node={child}
              depth={depth + 1}
              action={action}
            />
          ))}
        </div>
      )}
    </div>
  );
});

